import{_ as i,o as t,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt2202.jpg",l="/images/lekt2203.jpg",u="/images/lekt2201.jpg",s="/images/lekt2204.jpg",g=JSON.parse('{"title":"Lektion 22","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion22.md","filePath":"lektionen/lektion22.md"}'),o={name:"lektionen/lektion22.md"};function d(h,e,p,b,m,c){return t(),a("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-22" tabindex="-1">Lektion 22 <a class="header-anchor" href="#lektion-22" aria-label="Permalink to &quot;Lektion 22&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>22.1. Das Absolutivum (क्त्वा । ल्यप्)</li><li>22.2. Bildung des Absolutivums <ul><li>22.2.1. Verben ohne Präverb: Absolutiv auf -त्वा</li><li>22.2.2. Verben mit Präverb <ul><li>22.2.2.1. Wurzeln auf langen Vokal (außer -ā) oder auf Konsonant</li><li>22.2.2.2. Wurzeln auf -ā</li><li>22.2.2.3. Wurzeln, die in der Tiefstufe auf kurzes -i, -u, -ṛ auslauten</li><li>22.2.2.4. Wurzeln auf -am / -an, die in der Tiefstufe auf -a auslauten</li></ul></li></ul></li><li>22.3. Wortliste</li><li>22.4. Übung</li></ul><h2 id="_22-1-das-absolutivum-क्त्वा-।-ल्यप्" tabindex="-1">22.1. Das Absolutivum (क्त्वा । ल्यप्) <a class="header-anchor" href="#_22-1-das-absolutivum-क्त्वा-।-ल्यप्" aria-label="Permalink to &quot;22.1. Das Absolutivum (क्त्वा । ल्यप्)&quot;">​</a></h2><p>Will man in Sanskrit ausdrücken, dass eine Handlung des Agens (कर्तृ) einer anderen Handlung des Agens vorausgeht oder mit ihr als begleitender Umstand einhergeht, verwendet man das Absolutivum (क्त्वा । ल्यप्). Also</p><blockquote><p>&quot;nachdem er das getan hat, tut er jenes&quot; ; &quot;er tut das, dann tut er jenes&quot; ; &quot;als Folge von diesem tut er jenes&quot; ; &quot;ich kam, sah und siegte&quot; u. ä.</p></blockquote><p>Das Absolutivum ist ein Verbal-Adverb, d.h. es ist weder konjugierbar noch deklinierbar, es hat aber immer - von wenigen Ausnahmen abgesehen - denselben Agens (कर्तृ) wie die Handlung, der die durch das Absolutiv bezeichnete Handlung vorausgeht bzw. die es begleitet. Der Agens des Absolutiv staht also im Nominativ (प्रथमा)  oder Instrumentalis (तृतीया).</p><p>Neben den Komposita ist das Absolutiv eines der häufigsten Ausdrucksmittel im Sanskrit.</p><p>Bei der Übersetzung ins Deutsche vermeide man, ständig &quot;nachdem&quot; zu sagen. man verwende statt dessen die im Deutschen gebräuchlichen Ausdrucksweisen für zeitliche Anreihung.</p><p>Schema:</p><p>(nähere Bestimmung zum Absolutiv: Umstandsbestimmung, Objekt u.sw.) - Absolutiv - Absolutiv - ... - Absolutiv - ... Agens + Verbalsatz (im Aktiv oder Passiv)</p><p>Beispiele:</p><blockquote><p>गृहं प्रविश्य बालां दृष्ट्वा नरो वदति = Passivkonstruktion: गृहं प्रविश्य बालां दृष्ट्वा नरेणोद्यते = &quot;Der Mann betritt das Haus, sieht das kleine Mädchen und spricht es an.&quot;</p><p>Plural: गृहं प्रविश्य बालां दृष्ट्वा नरा वदन्ति ।</p></blockquote><h2 id="_22-2-bildung-des-absolutivums" tabindex="-1">22.2. Bildung des Absolutivums <a class="header-anchor" href="#_22-2-bildung-des-absolutivums" aria-label="Permalink to &quot;22.2. Bildung des Absolutivums&quot;">​</a></h2><ul><li>Verben ohne Präverb: Absolutiv auf -tvā</li><li>Verben mit Präverb: Absolutiv auf -ya bzw. -tya</li></ul><h3 id="_22-2-1-verben-ohne-praverb-absolutiv-auf-त्वा" tabindex="-1">22.2.1. Verben ohne Präverb: Absolutiv auf -त्वा <a class="header-anchor" href="#_22-2-1-verben-ohne-praverb-absolutiv-auf-त्वा" aria-label="Permalink to &quot;22.2.1. Verben ohne Präverb: Absolutiv auf -त्वा&quot;">​</a></h3><p>Bildung:</p><p>(meist) tiefstufige Wurzel in der Gestalt, die sie vor dem PPP hat + -tvā (-त्वा)</p><p>Nur das verneinende a- / an- verträgt sich mit dem Suffix -त्वा : अकृत्वा &quot;ohne getan zu haben&quot;</p><p>Beispiele:</p><blockquote><p>आप्त्वा &quot;nachdem er / sie / es / ich / du / wir / ihr / sie / wir beide / ihr beide / sie beide erreicht hat / hatte / haben / hatten&quot;</p><p>आसित्वा &quot;nachdem er (...) gesessen war / ist&quot;</p><p>इत्वा &quot;nachdem er (...) gegangen war / ist&quot;</p><p>स्थित्वा &quot;nachdem er (...) gestanden war / ist&quot;</p><p>जित्वा &quot;nachdem er (...) gesiegt hat / hatte&quot;</p><p>उक्त्वा &quot;nachdem er (...) gesprochen hat / hatte&quot;</p></blockquote><h3 id="_22-2-2-verben-mit-praverb" tabindex="-1">22.2.2. Verben mit Präverb <a class="header-anchor" href="#_22-2-2-verben-mit-praverb" aria-label="Permalink to &quot;22.2.2. Verben mit Präverb&quot;">​</a></h3><h4 id="_22-2-2-1-wurzeln-auf-langen-vokal-außer-a-oder-auf-konsonant" tabindex="-1">22.2.2.1. Wurzeln auf langen Vokal (außer -ā) oder auf Konsonant <a class="header-anchor" href="#_22-2-2-1-wurzeln-auf-langen-vokal-außer-a-oder-auf-konsonant" aria-label="Permalink to &quot;22.2.2.1. Wurzeln auf langen Vokal (außer -ā) oder auf Konsonant&quot;">​</a></h4><p>(meist) tiefstufige Wurzel + -ya</p><p>Beispiele:</p><blockquote><p>उपनीय &quot;nachdem er (...) herangeführt hat / hatte&quot;</p><p>प्रभूय &quot;nachdem er (...) herausgeragt ist / war&quot; &quot;nachdem er (...) Macht hatte&quot;</p><p>प्राप्य &quot;nachdem er (...) erlangt hat / hatte&quot;</p></blockquote><h4 id="_22-2-2-2-wurzeln-auf-a" tabindex="-1">22.2.2.2. Wurzeln auf -ā <a class="header-anchor" href="#_22-2-2-2-wurzeln-auf-a" aria-label="Permalink to &quot;22.2.2.2. Wurzeln auf -ā&quot;">​</a></h4><p>unverändert hochstufige Wurzel + -ya</p><p>Beispiel:</p><blockquote><p>उपस्थाय &quot;nachdem er (...) hingetreten war / ist&quot; ; (aber ohne Präverb: स्थित्वा)</p></blockquote><h4 id="_22-2-2-3-wurzeln-die-in-der-tiefstufe-auf-kurzes-i-u-r-auslauten" tabindex="-1">22.2.2.3. Wurzeln, die in der Tiefstufe auf kurzes -i, -u, -ṛ auslauten <a class="header-anchor" href="#_22-2-2-3-wurzeln-die-in-der-tiefstufe-auf-kurzes-i-u-r-auslauten" aria-label="Permalink to &quot;22.2.2.3. Wurzeln, die in der Tiefstufe auf kurzes -i, -u, -ṛ auslauten&quot;">​</a></h4><p>tiefstufige Wurzel + -tya</p><p>Beispiele:</p><blockquote><p>प्रस्तुत्य &quot;nachdem er (...) laut gepriesen hat / hatte&quot;</p><p>विस्मृत्य &quot;nachdem er (...) vergessen hat / hatte&quot;</p><p>संस्कृत्य &quot;nachdem er (...) fürs Opfer zubereitet hat / hatte&quot;</p></blockquote><h4 id="_22-2-2-4-wurzeln-auf-am-an-die-in-der-tiefstufe-auf-a-auslauten" tabindex="-1">22.2.2.4. Wurzeln auf -am / -an, die in der Tiefstufe auf -a auslauten <a class="header-anchor" href="#_22-2-2-4-wurzeln-auf-am-an-die-in-der-tiefstufe-auf-a-auslauten" aria-label="Permalink to &quot;22.2.2.4. Wurzeln auf -am / -an, die in der Tiefstufe auf -a auslauten&quot;">​</a></h4><p>Optionell:</p><p>Wurzel auf -am / -an + -ya</p><p>oder:</p><p>Wurzel auf -a + tya</p><p>Beispiel:</p><blockquote><p>विगम्य oder  विगत्य &quot;nachdem er (...) vergangen ist / war&quot;</p></blockquote><h2 id="_22-3-wortliste" tabindex="-1">22.3. Wortliste <a class="header-anchor" href="#_22-3-wortliste" aria-label="Permalink to &quot;22.3. Wortliste&quot;">​</a></h2><p>काम m.: Wunsch, Begehren ; erwünschte Gabe, Sinnenlust, Liebe, Liebesgott</p><blockquote><p>कामम् Akk. adverbiell: nach Wunsch, nach Herzenslust</p></blockquote><p><img src="'+r+'" alt=""><br> Abb.: कामदेवः , 19. Jhdt<br> [Bildquelle: Wikipedia, Public domain]</p><p>शक् 5 P शक्नोति Pass.शक्यते PPP शक्त Inf. शक्तुम् : fähig sein, können</p><p>davon:</p><blockquote><p>शक्ति f.: das Können, Vermögen, Fähigkeit, Kraft ; auch: göttliche Kraft, personifiziert als weibliche Begleiterin insbes. von शिव</p><p>शक्र m.: der Mächtige (Beiname von इन्द्र)</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: दुर्गाशक्तिः = दुर्गैव शक्तिः<br> Kolkatta = কলকাতা <br> [Bildquelle: The Eternity. -- <a href="http://www.flickr.com/photos/the_world_in_my_eyes/2914301330/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/the_world_in_my_eyes/2914301330/</a>. -- Zugriff am 2008-12-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>अर्ह 1 P अर्हति Pss. अर्ह्यते PPP अर्हित Inf. अर्हितुम् : etwas verdienen (zu etwas würdig sein), dürfen, verpflichtet sein zu, sollen (in der 2. Person wird अर्ह् + Infinitiv oft als milder Befehl verwendest: &quot;Du solltest&quot;)</p><blockquote><p>अर्हन्त् 3 Part. Präs. P: ein Würdiger. Im Buddhismus und Jainismus: jemand, der die endgültige Erlösung erreicht hat</p></blockquote><p>व्रत n.: Gelübde, religiöse Pflicht, religiöse Observanz (man verspricht der Gottheit etwas, um etwas von ihr zu bekommen. Beispiel: eine Mutter verspricht, ihre Tochter als Tempelprostituierte (देवदासी) hinzugeben, wenn ihre Tochter wieder gesund wird. Wichtige व्रत heute: Fasten ; Enthaltsamkeit von Speisen, die man liebt ; sexuelle Enthaltsamkeit ; Lesen heiliger Schriften ; Vollzug bestimmter Riten ; Speisung von Brahmanen u. ä. Kurz zu den व्रत : Walker, Hindu World Bd. II, S. 581f. Ausführlich: P. V. Kane: History of Dharmaśāstra Bd. 5,1 S. 1 - 462. Dort S. 253 - 462 Liste von व्रत und religiösen Festen (&quot;the following list ... does not calim to be thoroughly exhaustive&quot; !!!)</p><p>चर् 1 P चरति Pass. चर्यते PPP चरित Inf. चरितुम् : weiden, umhergehen, sich regen, sich bewegen, handeln, etwas ausüben, vollziehen (z.B. व्रतं चर् : ein Gelübde praktizieren, insbes. sexuelle Enthaltsamkeit)</p><p>davon:</p><blockquote><p>चर ३: beweglich ; n.: das Bewegliche = Tiere (im Unterschied zu den Pflanzen)</p><p>चरण n.,m.: Fuß</p><p>चरित n.: Lebenswandel, Lebenstaten</p><p>ब्रह्मचर्य n.: Vollzug des Veda (ब्रह्मन्) = Studium des Veda im ersten Lebensstadium (dem des ब्रह्मचारिन्), welches strenge sexuelle Enthaltsamkeit erfordert ; deshalb auch: sexuelle Enthaltsamkeit, zölibatärer Lebenswandel</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: धेनवश्चरन्ति<br> Goa = गोंय<br> [Bildquelle: Veebl. -- <a href="http://www.flickr.com/photos/veebl/2322214162/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/veebl/2322214162/</a>. -- Zugriff am 2008-12-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_22-4-ubung" tabindex="-1">22.4. Übung <a class="header-anchor" href="#_22-4-ubung" aria-label="Permalink to &quot;22.4. Übung&quot;">​</a></h2><p>A) Bilden und übersetzen Sie das Absolutiv zu folgenden Verben:</p><ol><li>आप्</li><li>प्राप्</li><li>समास्</li><li>आस्</li><li>समि</li><li>संस्कृ</li><li>कृ</li><li>गम्</li><li>उपगम् (2 Formen)</li><li>जि</li><li>विजि</li><li>तन्</li><li>दह्</li><li>उपदिश्</li><li>नी</li><li>पच्</li><li>उपपद्</li><li>पा १</li><li>प्रच्छ्</li><li>बुध्</li><li>सम्बुध्</li><li>भज्</li><li>भू</li><li>प्रभू</li><li>मन्</li><li>मुच्</li><li>विमुच्</li><li>मृ</li><li>यज्</li><li>लभ्</li><li>उपलभ्</li><li>वच्</li><li>प्रवच्</li><li>वद्</li><li>प्रवद्</li><li>हन्</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>अन्नं पक्त्वा ब्राह्मणदास्यत्ति ॥१॥</p><p>इष्टदेवतापूजां कृत्वेन्द्रादिदेवान्सद्ब्राह्मणाः स्तुवन्ति ॥२॥</p><p>प्रस्थाय रामः सपुत्रः सद्गुरुश्रवार्थेन ब्राह्मणग्रामं गच्छति ॥३॥</p><p>अनिष्ट्वा नरो भगवद्भक्तिमात्रेणापि मोक्षमाप्नोति ॥४॥</p><p>गृहगर्भं प्रविश्य ब्राह्मणपुत्रमुपस्थाय क्षत्रियशूरो वक्ति ॥५॥</p><p>सम्बुध्य दुःखाद्यार्यसत्यानि प्रोच्य सुगतो मोक्षमार्गेण नरान्नयति ॥६॥</p><p>मन्त्रं विस्मृत्य यजन्यज्ञदोषं करोति ॥७॥</p><p>धनं प्राप्य बुद्धमार्गभिक्षवो दुष्यन्ति ॥८॥</p><p>अनार्यशत्रुभिः संगत्य नरसिंहा विजयन्ते ॥९॥</p><p>पुण्यं कृत्वा सत्यमेवोदित्वा नरो नरकं नोपपद्यते ॥१०॥</p><p>C) Machen Sie aus obigen Sätzen (außer Sätze 8 und 10) Passivkonstruktionen</p><p><img src="'+s+'" alt=""><br> Abb.: अन्नं पक्त्वा ...<br> [Bildquelle: Curt Carnemark / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2183558378/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2183558378/</a>. -- Zugriff am 2008-12-12. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',73)])])}const k=i(o,[["render",d]]);export{g as __pageData,k as default};
